    const sync = function () { syncToolbarVisibility(dockRuntime) }
    const mo = new MutationObserver(sync)
    mo.observe(dockRuntime.toolbarEl, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ['hidden', 'style', 'class'],
    })
