/* ---- ui/form/colorInput.js ---- */
// aeditor.ui.colorInput - compact swatch + rich ARGB color picker.
//
// opts:
//   value:     string|int|signal   "#rrggbb", "#aarrggbb", or 24-bit int
//   onChange?: (v) => void
//   valueKind?: 'hex' | 'int'      (default 'hex')
